function CodeSnippetSkeleton({ className: containerClassName, type = "single", ...rest }) {
	const prefix = usePrefix();
	const className = classNames(containerClassName, {
		[`${prefix}--snippet`]: true,
		[`${prefix}--skeleton`]: true,
		[`${prefix}--snippet--single`]: type === "single",
		[`${prefix}--snippet--multi`]: type === "multi"
	});
	if (type === "single") return /* @__PURE__ */ jsx("div", {
		className,
		...rest,
		children: /* @__PURE__ */ jsx("div", {
			className: `${prefix}--snippet-container`,
			children: /* @__PURE__ */ jsx("span", {})
		})
	});
	if (type === "multi") return /* @__PURE__ */ jsx("div", {
		className,
		...rest,
		children: /* @__PURE__ */ jsxs("div", {
			className: `${prefix}--snippet-container`,
			children: [
				/* @__PURE__ */ jsx("span", {}),
				/* @__PURE__ */ jsx("span", {}),
				/* @__PURE__ */ jsx("span", {})
			]
		})
	});
}
